import{_ as d,o as r,c as e,ai as o}from"./chunks/framework.CaiDwmc7.js";const b=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"01 Геймдизайн/Пчелы/Классы пчел.md","filePath":"01 Геймдизайн/Пчелы/Классы пчел.md"}'),a={name:"01 Геймдизайн/Пчелы/Классы пчел.md"};function n(s,t,h,l,g,i){return r(),e("div",null,[...t[0]||(t[0]=[o('<h4 id="queen-матка" tabindex="-1">Queen - Матка <a class="header-anchor" href="#queen-матка" aria-label="Permalink to “Queen - Матка”">​</a></h4><p><strong>Средняя длительность жизни:</strong> 3-5 лет <strong>Максимальная:</strong> до 6-8 лет <strong>Развитие:</strong> из яйца во взрослую особь за 16 суток <strong>Питание:</strong> маточное молочко <strong>Особенность:</strong></p><ol><li>Живет дольше всех благодаря &quot;царскому питанию&quot; - питается маточным молочком на всех стадиях развития и в течение всей жизни.</li><li>Покидает улей только во время брачного вылета или при роении (когда пчелы собираются в рой и улетают из улья)</li><li>Обычно в пчеловодстве матку заменяют через 2 года, поскольку второй год жизни - пик яйценосности, а затем продуктивность матки снижается <strong>Функция:</strong> откладка яиц (до 2000 в сутки летом) <strong>Суточная смертность:</strong> 0% (если нет кризисных событий) <strong>Причины смерти:</strong> старость</li></ol><hr><h4 id="drones-трутни" tabindex="-1">Drones - Трутни <a class="header-anchor" href="#drones-трутни" aria-label="Permalink to “Drones - Трутни”">​</a></h4><p><strong>Средняя продолжительность жизни:</strong> 2-3 месяца в летний период <strong>Максимальная продолжительность жизни:</strong> 70 дней <strong>Развитие:</strong> из яйца во взрослую особь за 24 дня <strong>Питание:</strong> мед <strong>Особенности:</strong></p><ul><li>половозрелые с 10-14 дня жизни</li><li>живут до 54 дней в среднем, 70 дней максимум</li><li>если спарился с маткой погибает сразу (половые органы отрываются и остаются в матке)</li><li>если не спарился, осенью будет изгнан (после окончания медосбора), погибнет от голода и холода</li><li>потребляет в сутки в 4 раза больше меда, чем рабочая пчела</li><li>не могут есть сами, рабочие пчелы их кормят <strong>Суточная смертность:</strong> после спаривания высокая, иначе ~3% <strong>Причина смерти:</strong> спаривание или изгнание</li></ul><hr><h4 id="bee-workers-рабочие-пчелы" tabindex="-1">Bee_workers - Рабочие пчелы <a class="header-anchor" href="#bee-workers-рабочие-пчелы" aria-label="Permalink to “Bee_workers - Рабочие пчелы”">​</a></h4><p><strong>Продолжительность жизни</strong> различается в зависимости от <strong>сезона рождения</strong> и <strong>интенсивности труда</strong>:</p><table tabindex="0"><thead><tr><th>Сезон/Тип</th><th>Продолжительность жизни</th><th>Причина</th></tr></thead><tbody><tr><td>Летние пчелы (весенне-летнее рождение)</td><td>30-45 дней</td><td>Работа на износ: сбор нектара, выкармливание расплода, строительство. Крылья пчелы быстро портятся, организм истощается</td></tr><tr><td>В слабой семье</td><td>~26 дней</td><td>Мало рабочих -&gt; больше нагрузка</td></tr><tr><td>В сильной семье</td><td>до 60 дней</td><td>Равномерное распределение труда, достаточно питания</td></tr><tr><td>При отсутствии расплода</td><td>до 157 дней</td><td>Нет затрат питания и сил на выкармливание</td></tr><tr><td>Осенние/Зимующие (выводятся с конца августа по октябрь)</td><td>6-9 месяцев</td><td>Не работают, в теле накапливаются жировые резервы, не изнашиваются. Живут всю зиму, питаясь отложенным на зиму кормом, начинают активно работать в апреле и постепенно заменяются новым поколением</td></tr><tr><td><strong>Развитие:</strong> из яйца во взрослую особь за 21 день</td><td></td><td></td></tr><tr><td><strong>Питание:</strong> мед, перга</td><td></td><td></td></tr><tr><td><strong>Суточная смертность:</strong> 5% в активный сезон, 1% зимой</td><td></td><td></td></tr><tr><td><strong>Причины смерти:</strong> износ организма (лето), голод и холод (зима)</td><td></td><td></td></tr></tbody></table><h5 id="все-рабочие-пчелы-в-улье-делятся-на-две-основные-группы" tabindex="-1">Все рабочие пчелы в улье делятся на две основные группы: <a class="header-anchor" href="#все-рабочие-пчелы-в-улье-делятся-на-две-основные-группы" aria-label="Permalink to “Все рабочие пчелы в улье делятся на две основные группы:”">​</a></h5><p><strong>House_bees</strong> - внутренние пчелы, молодые, работают только внутри улья <strong>Foragers</strong> - фуражиры, <strong>летные пчелы</strong>, старшие пчелы, летают за ресурсами Пчела не может быть одновременно и внутренней пчелой, и фуражиром. Переход происходит один раз в жизни и необратим</p><table tabindex="0"><thead><tr><th>Возраст пчелы в днях</th><th>Роль</th><th>Что делает</th></tr></thead><tbody><tr><td>1-3</td><td>Уборщица</td><td>Чистит ячейки в рамках</td></tr><tr><td>3-10</td><td>Кормилица</td><td>Кормит расплод</td></tr><tr><td>5-12</td><td>Строительница</td><td>Строит новые соты</td></tr><tr><td>10-18</td><td>Приемщица</td><td>Принимает нектар</td></tr><tr><td>12-20</td><td>Вентиляторщица, охранница</td><td>Служба у входа (охраняет от вторженцев, следит за поступлением воздуха в улей)</td></tr><tr><td>&gt;20</td><td>Фуражир</td><td>Летает за ресурсами</td></tr><tr><td>Если фуражиров не хватает, молодые пчелы могут стать летными раньше (в 15-18 дней). Если летных избыток, переход в новый статус у внутренних пчел задерживается</td><td></td><td></td></tr></tbody></table><p>Поведенческие различия:</p><table tabindex="0"><thead><tr><th>Параметр</th><th>Внутренние пчелы</th><th>Фуражиры</th></tr></thead><tbody><tr><td>Где находятся</td><td>внутри уль, редко снаружи</td><td>снаружи, в полете</td></tr><tr><td>Продолжительность жизни</td><td>до перехода + 20-30 дней после</td><td>7-10 дней активной работы</td></tr><tr><td>Скорость износа</td><td>низкая (0.5-1% в день)</td><td>высокая (5-10% в день при полетах)</td></tr><tr><td>Потребление меда</td><td>0.01 кг в день</td><td>0.015 кг в день</td></tr><tr><td>Реакция на погоду</td><td>не реагируют</td><td>не летают в дождь и ветер</td></tr><tr><td>Ночью</td><td>работают в улье</td><td>отдыхают</td></tr></tbody></table><h5 id="специализации-фуражиров" tabindex="-1">Специализации фуражиров <a class="header-anchor" href="#специализации-фуражиров" aria-label="Permalink to “Специализации фуражиров”">​</a></h5><p>Фуражиры тоже делятся на подтипы:</p><table tabindex="0"><thead><tr><th>Тип</th><th>% от общего количества</th><th>Собирает</th><th>Особенности</th></tr></thead><tbody><tr><td>Нектарные</td><td>60-80%</td><td>Нектар</td><td>Основная масса, базовый маршрут</td></tr><tr><td>Пыльцевые</td><td>10-20%</td><td>Пыльцу</td><td>Садятся на цветы иначе,собирают комочки</td></tr><tr><td>Водоносы</td><td>5-10%</td><td>Воду</td><td>Активны в жару, летают к поилке</td></tr><tr><td>Прополисные</td><td>1-5%</td><td>Прополис</td><td>Работают на деревьях</td></tr><tr><td>Разведчицы</td><td>1-3%</td><td>Информацию</td><td>Ищут новые источники, передают информацию (танцуют)</td></tr><tr><td>Весной больше пыльцевых пчел (нужна перга для расплода)</td><td></td><td></td><td></td></tr><tr><td>В жару больше водоносов</td><td></td><td></td><td></td></tr><tr><td>При открытии нового медоноса разведчицы временно повышают активность</td><td></td><td></td><td></td></tr></tbody></table><p>Фуражиры умирают не только от возраста, но и от нагрузки. Каждый полет одного фуражира туда-сюда в среднем занимает: к улью рядом: 5-10 минут -&gt; 6-12 полетов в час -&gt; 300-600 полетов за жизнь к дальнему источнику: 30-60 минут -&gt; 1-2 полета в час -&gt; 50-100 полетов за жизнь одна летная пчела зи жизнь летает в среднем 50-100 часов</p>',20)])])}const p=d(a,[["render",n]]);export{b as __pageData,p as default};
